const User = require('../models/User');
const { generateAccessToken, generateRefreshToken } = require('../middleware/auth');
const { db } = require('../config/database');

class AuthController {
  // 用户注册
  static async register(req, res) {
    try {
      const { username, email, password, phone } = req.body;

      // 验证必需字段
      if (!username || !email || !password) {
        return res.status(400).json({ error: '用户名、邮箱和密码为必填项' });
      }

      // 验证用户名长度
      if (username.length < 3 || username.length > 20) {
        return res.status(400).json({ error: '用户名长度必须在3-20个字符之间' });
      }

      // 验证邮箱格式
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!emailRegex.test(email)) {
        return res.status(400).json({ error: '邮箱格式不正确' });
      }

      // 验证密码强度
      if (password.length < 6) {
        return res.status(400).json({ error: '密码长度至少6个字符' });
      }

      // 检查用户名是否已存在
      const existingUsername = await User.findByUsername(username);
      if (existingUsername) {
        return res.status(400).json({ error: '用户名已存在' });
      }

      // 检查邮箱是否已存在
      const existingEmail = await User.findByEmail(email);
      if (existingEmail) {
        return res.status(400).json({ error: '邮箱已被注册' });
      }

      // 创建用户
      const userData = { username, email, password };
      if (phone) {
        userData.phone = phone;
      }

      const user = await User.create(userData);

      // 获取用户积分
      const userPoints = await User.getUserPoints(user.id);

      // 生成令牌
      const accessToken = generateAccessToken(user);
      const refreshToken = generateRefreshToken(user);

      res.status(201).json({
        success: true,
        message: '注册成功',
        user: {
          id: user.id,
          username: user.username,
          email: user.email,
          phone: user.phone,
          role: user.role,
          display_name: user.display_name,
          avatar_url: user.avatar_url,
          motto: user.motto,
          privacy_mode: user.privacy_mode,
          points: userPoints,
          total_pixels: user.total_pixels,
          current_pixels: user.current_pixels,
          level: user.level,
          experience: user.experience,
          coins: user.coins,
          gems: user.gems,
          created_at: user.created_at
        },
        tokens: {
          accessToken,
          refreshToken
        }
      });

    } catch (error) {
      console.error('注册失败:', error);
      res.status(500).json({ error: '服务器内部错误' });
    }
  }

  // 用户登录
  static async login(req, res) {
    try {
      const { username, password, email } = req.body;

      // 验证必需字段
      if (!password || (!username && !email)) {
        return res.status(400).json({ error: '用户名/邮箱和密码为必填项' });
      }

      // 查找用户（包含密码哈希用于验证）
      let rawUser;
      if (username) {
        rawUser = await User.findByUsernameForAuth(username);
      } else {
        rawUser = await User.findByEmailForAuth(email);
      }

      if (!rawUser) {
        return res.status(401).json({ error: '用户名或密码错误' });
      }

      // 验证密码
      const isValidPassword = await User.verifyPassword(rawUser, password);
      if (!isValidPassword) {
        return res.status(401).json({ error: '用户名或密码错误' });
      }

      // 获取清理后的用户数据
      const user = User.sanitizeUser(rawUser);

      // 获取用户积分
      const userPoints = await User.getUserPoints(user.id);

      // 更新用户活动时间
      await User.updateActivity(user.id);

      // 生成令牌
      const accessToken = generateAccessToken(user);
      const refreshToken = generateRefreshToken(user);

      res.json({
        success: true,
        message: '登录成功',
        user: {
          id: user.id,
          username: user.username,
          email: user.email,
          phone: user.phone,
          role: user.role,
          display_name: user.display_name,
          avatar_url: user.avatar_url,
          motto: user.motto,
          privacy_mode: user.privacy_mode,
          points: userPoints,
          total_pixels: user.total_pixels,
          current_pixels: user.current_pixels,
          level: user.level,
          experience: user.experience,
          coins: user.coins,
          gems: user.gems,
          created_at: user.created_at
        },
        tokens: {
          accessToken: accessToken,
          refreshToken: refreshToken
        }
      });

    } catch (error) {
      console.error('登录失败:', error);
      res.status(500).json({ error: '服务器内部错误' });
    }
  }

  // 刷新令牌
  static async refreshToken(req, res) {
    try {
      const { refreshToken } = req.body;

      if (!refreshToken) {
        return res.status(400).json({ error: '刷新令牌为必填项' });
      }

      // 验证刷新令牌
      const { verifyRefreshToken } = require('../middleware/auth');
      const decoded = verifyRefreshToken(refreshToken);

      if (!decoded) {
        return res.status(403).json({ error: '刷新令牌无效或已过期' });
      }

      // 获取用户信息
      const user = await User.findById(decoded.id);
      if (!user) {
        return res.status(403).json({ error: '用户不存在' });
      }

      // 生成新的令牌
      const newAccessToken = generateAccessToken(user);
      const newRefreshToken = generateRefreshToken(user);

      res.json({
        success: true,
        tokens: {
          accessToken: newAccessToken,
          refreshToken: newRefreshToken
        }
      });

    } catch (error) {
      console.error('刷新令牌失败:', error);
      res.status(500).json({ error: '服务器内部错误' });
    }
  }

  // 获取当前用户信息
  static async getCurrentUser(req, res) {
    try {
      const user = req.user;
      
      // 获取用户的联盟信息
      let alliance = null;
      try {
        const allianceResult = await db('alliance_members as am')
          .join('alliances as a', 'am.alliance_id', 'a.id')
          .where('am.user_id', user.id)
          .where('am.status', 'active')
          .select('a.id', 'a.name', 'a.description', 'a.flag', 'a.color', 'am.role', 'am.joined_at')
          .first();
        
        if (allianceResult) {
          alliance = {
            id: allianceResult.id,
            name: allianceResult.name,
            description: allianceResult.description,
            flag: allianceResult.flag,
            color: allianceResult.color,
            role: allianceResult.role,
            joined_at: allianceResult.joined_at
          };
        }
      } catch (allianceError) {
        console.log('获取联盟信息失败:', allianceError);
        // 不影响主要功能，继续执行
      }
      
      res.json({
        success: true,
        user: {
          id: user.id,
          username: user.username,
          email: user.email,
          phone: user.phone,
          points: await User.getUserPoints(user.id),
          created_at: user.created_at,
          last_activity: user.last_activity,
          alliance: alliance
        }
      });

    } catch (error) {
      console.error('获取用户信息失败:', error);
      res.status(500).json({ error: '服务器内部错误' });
    }
  }

  // 更新用户信息
  static async updateProfile(req, res) {
    try {
      const { username, email, phone } = req.body;
      const userId = req.user.id;

      // 验证用户名长度
      if (username && (username.length < 3 || username.length > 20)) {
        return res.status(400).json({ error: '用户名长度必须在3-20个字符之间' });
      }

      // 验证邮箱格式
      if (email) {
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        if (!emailRegex.test(email)) {
          return res.status(400).json({ error: '邮箱格式不正确' });
        }
      }

      // 检查用户名是否已被其他用户使用
      if (username) {
        const existingUser = await User.findByUsername(username);
        if (existingUser && existingUser.id !== userId) {
          return res.status(400).json({ error: '用户名已存在' });
        }
      }

      // 检查邮箱是否已被其他用户使用
      if (email) {
        const existingUser = await User.findByEmail(email);
        if (existingUser && existingUser.id !== userId) {
          return res.status(400).json({ error: '邮箱已被注册' });
        }
      }

      // 更新用户信息
      const updateData = {};
      if (username) updateData.username = username;
      if (email) updateData.email = email;
      if (phone !== undefined) updateData.phone = phone;

      await db('users')
        .where({ id: userId })
        .update({
          ...updateData,
          updated_at: db.fn.now()
        });

      // 获取更新后的用户信息
      const updatedUser = await User.findById(userId);

      res.json({
        success: true,
        message: '用户信息更新成功',
        user: {
          id: updatedUser.id,
          username: updatedUser.username,
          email: updatedUser.email,
          phone: updatedUser.phone,
          points: updatedUser.points,
          created_at: updatedUser.created_at,
          last_activity: updatedUser.last_activity
        }
      });

    } catch (error) {
      console.error('更新用户信息失败:', error);
      res.status(500).json({ error: '服务器内部错误' });
    }
  }

  // 发送验证码（模拟）
  static async sendVerificationCode(req, res) {
    try {
      const { phone, type } = req.body;

      if (!phone || !type) {
        return res.status(400).json({ error: '手机号和类型为必填项' });
      }

      if (!['register', 'login'].includes(type)) {
        return res.status(400).json({ error: '类型必须是 register 或 login' });
      }

      // 验证手机号格式（简单验证）
      const phoneRegex = /^1[3-9]\d{9}$/;
      if (!phoneRegex.test(phone)) {
        return res.status(400).json({ error: '手机号格式不正确' });
      }

      // 生成6位验证码
      const code = Math.floor(100000 + Math.random() * 900000).toString();

      // 存储验证码到Redis（这里简化处理，实际应该存储到Redis）
      // 在实际项目中，这里应该调用短信服务发送验证码
      console.log(`验证码已发送到 ${phone}: ${code}`);

      res.json({
        success: true,
        message: '验证码已发送',
        code: code // 开发环境返回验证码，生产环境应该移除
      });

    } catch (error) {
      console.error('发送验证码失败:', error);
      res.status(500).json({ error: '服务器内部错误' });
    }
  }

  // 验证验证码
  static async verifyCode(req, res) {
    try {
      const { phone, code } = req.body;

      if (!phone || !code) {
        return res.status(400).json({ error: '手机号和验证码为必填项' });
      }

      // 这里应该从Redis中获取验证码进行验证
      // 简化处理，直接返回成功
      res.json({
        success: true,
        message: '验证码验证成功'
      });

    } catch (error) {
      console.error('验证验证码失败:', error);
      res.status(500).json({ error: '服务器内部错误' });
    }
  }

  // 用户登出
  static async logout(req, res) {
    try {
      // 在实际项目中，这里应该将token加入黑名单
      // 简化处理，直接返回成功
      res.json({
        success: true,
        message: '登出成功'
      });

    } catch (error) {
      console.error('登出失败:', error);
      res.status(500).json({ error: '服务器内部错误' });
    }
  }
}

module.exports = AuthController;
